// Parse GLM-5 response and format notification
const response = $input.item.json;
const issueKey = $('Extract Issue Data').item.json.issueKey;
const summary = $('Extract Issue Data').item.json.summary;
const issueType = $('Extract Issue Data').item.json.issueType;
const priority = $('Extract Issue Data').item.json.priority;
const status = $('Extract Issue Data').item.json.status;
const eventType = $('Extract Issue Data').item.json.eventType;

let aiSummary = '';
if (response.content && Array.isArray(response.content)) {
  aiSummary = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response === 'string') {
  aiSummary = response;
}

const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

// Determine emoji-free priority indicator
const priorityIndicator = {
  'Highest': '[!!!]',
  'High': '[!!]',
  'Medium': '[!]',
  'Low': '[-]',
  'Lowest': '[.]'
};

const notificationText = `*${issueKey}: ${summary}*\nType: ${issueType} | Priority: ${priority} ${priorityIndicator[priority] || ''} | Status: ${status}\nEvent: ${eventType}\n\n*AI Summary:*\n${aiSummary}\n\n_Jira: https://{{JIRA_HOST}}/browse/${issueKey} | Tokens: ${inputTokens}/${outputTokens}_`;

return [{
  json: {
    issueKey,
    summary,
    aiSummary,
    inputTokens,
    outputTokens,
    notificationText
  }
}];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
